SELECT test_conducted_by, SUM(num_tests) AS total_tests_conducted
FROM testing_data
GROUP BY test_conducted_by;

SELECT *
FROM test_takers
WHERE gender = 'Male' OR gender = 'Female';

SELECT AVG(positivity_rate) AS average_positivity_rate
FROM testing_data
WHERE test_conducted_by = 'Alice Johnson';

SELECT tt.test_type_name
FROM test_types tt
WHERE tt.test_accuracy > (SELECT AVG(test_accuracy) FROM test_types);

SELECT td.test_id, td.date, td.test_type_id
FROM testing_data td
WHERE td.positivity_rate > (SELECT AVG(positivity_rate) FROM testing_data);

SELECT frequency_id, frequency_name
FROM test_frequencies
WHERE frequency_interval = 'every 7 days';

SELECT name
FROM test_takers
WHERE test_taker_id = 1;
